  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 30, 'אני מלווה תהליכי פתרון קונפליקטים והפחתת איומים.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 31, 'אני מסייע בהקניית כלים לפיתוח מיומנויות הגנה עצמית.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 32, 'אני מחזק את היכולת לבצע חקירות מודיעיניות.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 33, 'אני מלווה תהליכי הערכת מצב והיערכות מבצעית.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 34, 'אני מסייע ביצירת סביבה מאורגנת ומוגנת.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 35, 'אני מחזק את היכולת לנהל משימות ביטחון בצורה מקצועית.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 36, 'אני מלווה תהליכי הדרכה והכשרה למפקדים וצוותים.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 37, 'אני מסייע בפיתוח פרוטוקולים ונהלים לבטיחות.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 38, 'אני מחזק את היכולת לשלב ידע טכנולוגי בפעילות ביטחונית.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 39, 'אני מלווה תהליכי חקירה ופיקוח מתקדמים.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 40, 'אני מסייע בשמירה על גבולות החוק והסדר הציבורי.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 41, 'אני מחזק את היכולת לפעול בצורה יעילה במצבי חירום.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 42, 'אני מלווה תהליכי ניתוח מידע והסקת מסקנות.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 43, 'אני מסייע באיתור ואכיפת עבירות פליליות.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 44, 'אני מחזק את היכולת להגן על אוכלוסיות פגיעות.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 45, 'אני מלווה תהליכי תכנון מבצעי ואבטחה.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 46, 'אני מסייע בפיתוח יכולות שיתוף פעולה בין ארגוני ביטחון.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 47, 'אני מחזק את היכולת לנהל סיכונים באופן פרואקטיבי.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 48, 'אני מלווה תהליכי קבלת החלטות מהירה ומדויקת.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 49, 'אני מסייע בהגברת מודעות הציבור לנושאי ביטחון.'),
  (25, 'הגנה וביטחון', 'משטרה, צבא, חוקר פרטי', 50, 'אני מחזק את היכולת להשפיע על שמירה על שלום וביטחון בצורה מקצועית ומעצימה.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 1, 'אני מסייע בשמירה על בריאותם של בעלי החיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 2, 'אני מחזק את היכולת להבין את צרכי בעלי החיים ולהתאים להם טיפול מתאים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 3, 'אני מלווה תהליכי טיפוח והקניית הרגלים בריאים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 4, 'אני מסייע בהדרכה וחינוך בעלי חיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 5, 'אני מחזק את היכולת ליצור קשר אמון והבנה עם בעלי החיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 6, 'אני מלווה תהליכי טיפול רפואי ומניעתי.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 7, 'אני מסייע באבחון מוקדם של מחלות ובעיות בריאותיות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 8, 'אני מחזק את היכולת לפתח תוכניות אילוף מותאמות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 9, 'אני מלווה תהליכי שיקום ושחרור בעלי חיים לפעילות תקינה.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 10, 'אני מסייע ביצירת סביבה בטוחה ומזמינה לבעלי החיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 11, 'אני מחזק את היכולת לנהל חוות וטרינריות בצורה מקצועית.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 12, 'אני מלווה תהליכי אימון והכוונה לבעלי חיים ומשפחותיהם.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 13, 'אני מסייע בשיפור איכות החיים של בעלי החיים והסביבה שלהם.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 14, 'אני מחזק את היכולת לזהות סימני לחץ או מחלה אצל בעלי החיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 15, 'אני מלווה תהליכי הקניית הרגלים טובים וציות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 16, 'אני מסייע ביצירת תוכניות טיפוח ורווחה מותאמות אישית.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 17, 'אני מחזק את היכולת לטפל במצבי חירום רפואיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 18, 'אני מלווה תהליכי חינוך והעצמה של מטפלים ובעלי חיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 19, 'אני מסייע בהגברת מודעות ציבורית לבריאות ורווחת בעלי חיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 20, 'אני מחזק את היכולת ליצור קשרים בין בעלי חיים לבני אדם בצורה חיובית.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 21, 'אני מלווה תהליכי שיקום בעלי חיים פגועים או נטושים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 22, 'אני מסייע בפיתוח מיומנויות טיפול והדרכה מתקדמות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 23, 'אני מחזק את היכולת להנחות חיות בסביבה קבוצתית או חינוכית.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 24, 'אני מלווה תהליכי הכשרה לאנשי מקצוע בתחום החיות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 25, 'אני מסייע ביצירת סביבה תומכת ומזינה לצמיחה וללמידה של בעלי החיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 26, 'אני מחזק את היכולת לשפר את הבריאות הפיזית והנפשית של בעלי החיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 27, 'אני מלווה תהליכי אילוף לפי צרכים אישיים והתנהגותיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 28, 'אני מסייע ביצירת תוכניות טיפול ושיקום ארוכות טווח.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 29, 'אני מחזק את היכולת לזהות ולמנוע בעיות בריאותיות בעתיד.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 30, 'אני מלווה תהליכי הדרכה והעצמה של בעלי חיים בסביבה טבעית.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 31, 'אני מסייע בהגנה על בעלי חיים מפגיעה או הזנחה.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 32, 'אני מחזק את היכולת לאבחן ולטפל במצבים מורכבים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 33, 'אני מלווה תהליכי חינוך להעצמת המטפלים בבעלי חיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 34, 'אני מסייע ביצירת חיבור רגשי בין בעלי חיים ובני אדם.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 35, 'אני מחזק את היכולת לנהל סביבה בטוחה ומאורגנת לבעלי חיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 36, 'אני מלווה תהליכי פיתוח תוכניות אילוף חדשניות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 37, 'אני מסייע בהעצמת צוותי טיפול במקצועיות ובמיומנויות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 38, 'אני מחזק את היכולת לפתח חוסן ובריאות נפשית אצל בעלי החיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 39, 'אני מלווה תהליכי טיפול חינוכי עם חיות בסביבה טיפולית.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 40, 'אני מסייע ביצירת תוכניות מניעה ומעקב רפואי.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 41, 'אני מחזק את היכולת לזהות התנהגויות בעייתיות ולשפר אותן.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 42, 'אני מלווה תהליכי שילוב בעלי חיים בפעילויות חינוכיות וקהילתיות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 43, 'אני מסייע בהגברת מודעות הציבור לאימוץ ואחריות על בעלי חיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 44, 'אני מחזק את היכולת לעבוד בצוותי טיפול מקצועיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 45, 'אני מלווה תהליכי ייעוץ מקצועי לאנשים עם חיות מחמד.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 46, 'אני מסייע ביצירת חוויות חיוביות ומעשירות לבעלי החיים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 47, 'אני מחזק את היכולת לפתח תוכניות טיפול אינטגרטיביות.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 48, 'אני מלווה תהליכי הדרכה ושיתוף ידע עם מטפלים אחרים.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 49, 'אני מסייע ביצירת מערכת יחסים הרמונית ומועילה בין בעלי חיים לבני אדם.'),
  (26, 'טיפול בבעלי חיים', 'וטרינריה, אילוף כלבים, חוות סוסים', 50, 'אני מחזק את היכולת להשפיע על רווחת בעלי החיים באופן משמעותי ומקצועי.'),
  (27, 'עבודות כפיים ותעשייה', 'נגרות, מסגרות, ריתוך', 1, 'אני מייצר ומעצים יצירות חומר בצורה מדויקת ואסתטית.'),
  (27, 'עבודות כפיים ותעשייה', 'נגרות, מסגרות, ריתוך', 2, 'אני מחזק את היכולת ליצור מוצרים שימושיים ועמידים.'),
  (27, 'עבודות כפיים ותעשייה', 'נגרות, מסגרות, ריתוך', 3, 'אני מלווה תהליכי עבודה ידנית עם תשומת לב לפרטים.'),
  (27, 'עבודות כפיים ותעשייה', 'נגרות, מסגרות, ריתוך', 4, 'אני מסייע בפיתוח מיומנויות טכניות ומקצועיות.'),
  (27, 'עבודות כפיים ותעשייה', 'נגרות, מסגרות, ריתוך', 5, 'אני מחזק את היכולת לחדש ולהתאים פתרונות בהתאם לצורך.'),
  (27, 'עבודות כפיים ותעשייה', 'נגרות, מסגרות, ריתוך', 6, 'אני מלווה תהליכי תכנון והנדסה של מוצרים.'),
  (27, 'עבודות כפיים ותעשייה', 'נגרות, מסגרות, ריתוך', 7, 'אני מסייע ביצירת חיבור בין רעיון למוצר מוחשי.'),
  (27, 'עבודות כפיים ותעשייה', 'נגרות, מסגרות, ריתוך', 8, 'אני מחזק את היכולת לעבוד בצורה בטוחה ומבוקרת בסדנאות.'),
