-- Create designation_statements table and populate from docs/sentences.json
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_tables WHERE tablename = 'designation_statements') THEN
    CREATE TABLE designation_statements (
      id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
      occupation_serial INT NOT NULL,
      occupation_title TEXT NOT NULL,
      occupation_description TEXT,
      statement_serial INT NOT NULL CHECK (statement_serial >= 1 AND statement_serial <= 50),
      statement TEXT NOT NULL
    );
  END IF;
END $$;

-- Useful index
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_indexes WHERE indexname = 'idx_designation_statements_occupation_serial') THEN
    CREATE INDEX idx_designation_statements_occupation_serial ON designation_statements(occupation_serial);
  END IF;
END $$;

-- Enable RLS and allow read for everyone
DO $$
BEGIN
  EXECUTE 'ALTER TABLE designation_statements ENABLE ROW LEVEL SECURITY';
EXCEPTION WHEN OTHERS THEN
END $$;

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Designation statements are viewable by everyone') THEN
    CREATE POLICY "Designation statements are viewable by everyone"
    ON designation_statements FOR SELECT USING (true);
  END IF;
END $$;







